def generate_dummy_pdf_content(invoice_id):
    """
    Generates a very simple dummy PDF content in memory.
    In a real application, you would load the actual PDF file.
    """
    try:
        from reportlab.pdfgen import canvas
        from reportlab.lib.pagesizes import letter
        buffer = io.BytesIO()
        p = canvas.Canvas(buffer, pagesize=letter)
        p.drawString(100, 750, f"Invoice ID: {invoice_id}")
        p.drawString(100, 730, "This is a dummy invoice for demonstration purposes.")
        p.drawString(100, 710, "Thank you for your business!")
        p.showPage()
        p.save()
        buffer.seek(0)
        return buffer
    except ImportError:
        # Fallback if reportlab is not installed (e.g., provide a basic text file)
        print("Warning: reportlab not found. Providing a text file instead of PDF.")
        return io.BytesIO(f"Invoice ID: {invoice_id}\nThis is a dummy invoice (PDF generation library not found).\n".encode('utf-8'))


